/*################## 头文件依赖和说明 #################

fmt:格式化输出
atomic:多线程安全标志位
chrono:高精度时间
json:用于向Plotter发送数据
OpenCV:图像处理与显示
Thred:多线程

camera.hpp：相机驱动
gimbal.hpp：云台通信
planner.hpp： 云台规划
solver.hpp：弹道解算 / 坐标变换
tracker.hpp：多目标跟踪
yolo.hpp：YOLO检测
tools:工具类（日志、线程队列、绘图等）
*/


#include <fmt/core.h> 

#include <atomic>
#include <chrono>
#include <nlohmann/json.hpp>
#include <opencv2/opencv.hpp>
#include <thread>

#include "io/camera.hpp"
#include "io/gimbal/gimbal.hpp"
#include "tasks/auto_armor/planner/planner.hpp"
#include "tasks/auto_armor/solver.hpp"
#include "tasks/auto_armor/tracker.hpp"
#include "tasks/auto_armor/yolo.hpp"
#include "tools/exiter.hpp"
#include "tools/img_tools.hpp"
#include "tools/logger.hpp"
#include "tools/math_tools.hpp"
#include "tools/plotter.hpp"
#include "tools/thread_safe_queue.hpp"

using namespace std::chrono_literals;

/*##############提供yaml文件##################

必须提供一个 YAML 配置文件路径
包含相机、云台、模型、参数等配置

*/
const std::string keys =
  "{help h usage ? |                        | 输出命令行参数说明}"
  "{@config-path   | /home/xu/auto_aim/configs/test.yaml   | 位置参数，yaml配置文件路径 }";

int main(int argc, char * argv[])
{
  tools::Exiter exiter;
  tools::Plotter plotter;

  cv::CommandLineParser cli(argc, argv, keys);
  auto config_path = cli.get<std::string>(0);
  if (cli.has("help") || config_path.empty()) {
    cli.printMessage();
    return 0;
  }

  /*##############系统对象初始化################

  Camera:读取相机图像
  Gimbal:获取云台状态+发送控制指令
  YOLO：装甲板检测
  Tracker：多目标EKF跟踪
  Solver：坐标变换+弹道解算
  Planner：云台角度、速度、加速度、开火决策

  */

  io::Gimbal gimbal(config_path);
  io::Camera camera(config_path);

  auto_aim::YOLO yolo(config_path, true);
  auto_aim::Solver solver(config_path);
  auto_aim::Tracker tracker(config_path, solver);
  auto_aim::Planner planner(config_path);

  /*###############线程安全目标队列(视觉 → 控制)###############

  target_queue：队列容量=1
  始终保持新目标
  std::optional表示：有目标：射击；无目标：停止搜索
  */

  tools::ThreadSafeQueue<std::optional<auto_aim::Target>, true> target_queue(1);
  target_queue.push(std::nullopt);

  std::atomic<bool> quit = false;

  /*###############规划 & 云台控制线程（核心闭环）###############


  这是一个10ms周期的实时控制线程
  1.target,gs:获取目标 & 云台状态,gs:云台角度、角速度、子弹计数、弹速等
  2.plan:规划器输出控制量,yaw/pitch,角加速度，是否开火，目标角度
  3.gimbal.send：向云台发送指令
  4.auto fired：判断是否真实击发
  5.data:记录并绘图（Plotter）完整记录云台状态、目标状态、规划输出

  */
  auto plan_thread = std::thread([&]() {
    auto t0 = std::chrono::steady_clock::now();
    uint16_t last_bullet_count = 0;

    // 简化导航信息
    float nav_x = 0, nav_y = 0, nav_w = 0;

    while (!quit) {
      auto target = target_queue.front();
      auto gs = gimbal.state();
      auto plan = planner.plan(target, gs.bullet_speed);

      // 第二步：传参数量与占位符完全匹配，打印完整数据
      tools::logger()->info("control={}, fire={}, yaw={:.2f}, pitch={:.2f}", 
                            plan.control, plan.fire, plan.yaw * 57.3f, plan.pitch * 57.3f);

      if (plan.control) {
          // 计算相对角度差值
          float pitch_diff = gs.pitch * 57.3f - plan.pitch * 57.3f;  // 目标角度 - 当前角度
          float yaw_diff = gs.yaw * 57.3f - plan.yaw * 57.3f;  // 目标角度 - 当前角度

          // 发送相对角度差值
          gimbal.send(plan.control, plan.fire,
                       -yaw_diff, 0, 0,        // yaw角度
                       pitch_diff, 0, 0,      // pitch相对调整量
                       nav_x, nav_y, nav_w);

          // 添加调试信息
          tools::logger()->info("pitch: target={:.2f}°, current={:.2f}°, diff={:.2f}°", 
                                plan.pitch * 57.3f, gs.pitch * 57.3f, pitch_diff);
      } else {
          // 无目标：全部发0
          gimbal.send(false, false,
                       0, 0, 0,
                       0, 0, 0,
                       0, 0, 0);
      }

      //下位机传的子弹数量
      auto fired = gs.bullet_count > last_bullet_count;
      last_bullet_count = gs.bullet_count;

      nlohmann::json data;
      data["t"] = tools::delta_time(std::chrono::steady_clock::now(), t0);

      data["gimbal_yaw"] = gs.yaw;
      data["gimbal_yaw_vel"] = gs.yaw_vel;
      data["gimbal_pitch"] = gs.pitch;
      data["gimbal_pitch_vel"] = gs.pitch_vel;

      data["target_yaw"] = plan.target_yaw;
      data["target_pitch"] = plan.target_pitch;

      data["plan_yaw"] = plan.yaw;
      data["plan_yaw_vel"] = plan.yaw_vel;
      data["plan_yaw_acc"] = plan.yaw_acc;

      data["plan_pitch"] = plan.pitch;
      data["plan_pitch_vel"] = plan.pitch_vel;
      data["plan_pitch_acc"] = plan.pitch_acc;

      data["fire"] = plan.fire ? 1 : 0;
      data["fired"] = fired ? 1 : 0;

      if (target.has_value()) {
        data["target_z"] = target->ekf_x()[4];   //z
        data["target_vz"] = target->ekf_x()[5];  //vz
      }

      if (target.has_value()) {
        data["w"] = target->ekf_x()[7];
      } else {
        data["w"] = 0.0;
      }

      plotter.plot(data);

      std::this_thread::sleep_for(10ms);
    }
  });

  /*###############主线程：视觉处理流程##############

  camera.read：读相机
  auto q：获取云台姿态（四元数）
  solver.set_R_gimbal2world(q)：更新坐标变换：云台 → 世界
  yolo：yolo检测，输出装甲板的检测框
  targets：跟踪EKF
  !targets.empty()：将目标送入控制线程，通常排序后取最近/威胁最大的
  */
  cv::Mat img;
  std::chrono::steady_clock::time_point t;

  while (!exiter.exit()) {
    camera.read(img, t);
    auto q = gimbal.q(t);
    auto gs = gimbal.state();  // 获取云台状态

    solver.set_R_gimbal2world(q);
    auto armors = yolo.detect(img);
    auto targets = tracker.track(armors, t, gs.prior_target);  // 传入priority_target
    if (!targets.empty())
      target_queue.push(targets.front());
    else
      target_queue.push(std::nullopt);

    if (!targets.empty()) {
      //取出列表中的第一个目标,赋值给target
      auto target = targets.front();

      /*##############调试：重投影可视化（非常关键）##########
      当前装甲板重投影（绿色）

      */
      // 当前帧target更新后
      std::vector<Eigen::Vector4d> armor_xyza_list = target.armor_xyza_list();
      for (const Eigen::Vector4d & xyza : armor_xyza_list) {
        auto image_points =
          solver.reproject_armor(xyza.head(3), xyza[3], target.armor_type, target.name);
        tools::draw_points(img, image_points, {0, 255, 0});
      }

      Eigen::Vector4d aim_xyza = planner.debug_xyza;
      auto image_points =
        solver.reproject_armor(aim_xyza.head(3), aim_xyza[3], target.armor_type, target.name);
      tools::draw_points(img, image_points, {0, 0, 255});
    }

    // 添加串口数据可视化显示
    // gs变量已经在上面声明过了，这里直接使用

    cv::resize(img, img, {}, 0.5, 0.5);  // 显示时缩小图片尺寸

    // 创建串口数据显示区域，宽度与缩放后的图像匹配
    int img_width = img.cols;  // 获取缩放后图像的宽度
    cv::Mat serial_overlay = cv::Mat::zeros(300, img_width, CV_8UC3);

    // 接收数据显示 (左侧，绿色)
    cv::putText(serial_overlay, "=== RX DATA ===", cv::Point(10, 25), 
                cv::FONT_HERSHEY_SIMPLEX, 0.6, cv::Scalar(0, 255, 0), 2);
    cv::putText(serial_overlay, fmt::format("Yaw: {:.2f} deg", gs.yaw * 57.3f), 
                cv::Point(10, 50), cv::FONT_HERSHEY_SIMPLEX, 0.5, cv::Scalar(0, 255, 0), 1);
    cv::putText(serial_overlay, fmt::format("Pitch: {:.2f} deg", gs.pitch * 57.3f), 
                cv::Point(10, 70), cv::FONT_HERSHEY_SIMPLEX, 0.5, cv::Scalar(0, 255, 0), 1);
    cv::putText(serial_overlay, fmt::format("Yaw Vel: {:.2f} deg/s", gs.yaw_vel * 57.3f), 
                cv::Point(10, 90), cv::FONT_HERSHEY_SIMPLEX, 0.5, cv::Scalar(0, 255, 0), 1);
    cv::putText(serial_overlay, fmt::format("Pitch Vel: {:.2f} deg/s", gs.pitch_vel * 57.3f), 
                cv::Point(10, 110), cv::FONT_HERSHEY_SIMPLEX, 0.5, cv::Scalar(0, 255, 0), 1);
    cv::putText(serial_overlay, fmt::format("Bullet Speed: {:.1f} m/s", gs.bullet_speed), 
                cv::Point(10, 130), cv::FONT_HERSHEY_SIMPLEX, 0.5, cv::Scalar(0, 255, 0), 1);
    cv::putText(serial_overlay, fmt::format("Bullet Count: {}", gs.bullet_count), 
                cv::Point(10, 150), cv::FONT_HERSHEY_SIMPLEX, 0.5, cv::Scalar(0, 255, 0), 1);
    cv::putText(serial_overlay, fmt::format("Health: {}", gs.health), 
                cv::Point(10, 170), cv::FONT_HERSHEY_SIMPLEX, 0.5, cv::Scalar(0, 255, 0), 1);
    cv::putText(serial_overlay, fmt::format("Game State: {}", gs.game_state), 
                cv::Point(10, 190), cv::FONT_HERSHEY_SIMPLEX, 0.5, cv::Scalar(0, 255, 0), 1);

    // 发送数据显示 (右侧，蓝色) - 获取当前的plan数据
    auto current_target = target_queue.front();
    auto plan = planner.plan(current_target, gs.bullet_speed);

    // 计算右侧显示位置，确保不超出图像宽度
    int right_x = std::min(img_width / 2 + 10, img_width - 300);

    cv::putText(serial_overlay, "=== TX DATA ===", cv::Point(right_x, 25), 
                cv::FONT_HERSHEY_SIMPLEX, 0.6, cv::Scalar(255, 100, 0), 2);
    cv::putText(serial_overlay, fmt::format("Control: {}", plan.control ? "ON" : "OFF"), 
                cv::Point(right_x, 50), cv::FONT_HERSHEY_SIMPLEX, 0.5, cv::Scalar(255, 100, 0), 1);
    cv::putText(serial_overlay, fmt::format("Fire: {}", plan.fire ? "YES" : "NO"), 
                cv::Point(right_x, 70), cv::FONT_HERSHEY_SIMPLEX, 0.5, cv::Scalar(255, 100, 0), 1);
    cv::putText(serial_overlay, fmt::format("plan Yaw: {:.2f} deg", plan.yaw * 57.3f), 
                cv::Point(right_x, 90), cv::FONT_HERSHEY_SIMPLEX, 0.5, cv::Scalar(255, 100, 0), 1);
    cv::putText(serial_overlay, fmt::format("plan Pitch: {:.2f} deg", plan.pitch * 57.3f), 
                cv::Point(right_x, 110), cv::FONT_HERSHEY_SIMPLEX, 0.5, cv::Scalar(255, 100, 0), 1);
    cv::putText(serial_overlay, fmt::format("Yaw Vel: {:.2f} deg/s", plan.yaw_vel * 57.3f), 
                cv::Point(right_x, 130), cv::FONT_HERSHEY_SIMPLEX, 0.5, cv::Scalar(255, 100, 0), 1);
    cv::putText(serial_overlay, fmt::format("Pitch Vel: {:.2f} deg/s", plan.pitch_vel * 57.3f), 
                cv::Point(right_x, 150), cv::FONT_HERSHEY_SIMPLEX, 0.5, cv::Scalar(255, 100, 0), 1);
    cv::putText(serial_overlay, fmt::format("Yaw Acc: {:.2f} deg/s²", plan.yaw_acc * 57.3f), 
                cv::Point(right_x, 170), cv::FONT_HERSHEY_SIMPLEX, 0.5, cv::Scalar(255, 100, 0), 1);
    cv::putText(serial_overlay, fmt::format("Pitch Acc: {:.2f} deg/s²", plan.pitch_acc * 57.3f), 
                cv::Point(right_x, 190), cv::FONT_HERSHEY_SIMPLEX, 0.5, cv::Scalar(255, 100, 0), 1);

    // 连接状态显示 (居中)
    cv::Scalar connection_color = gimbal.is_connected() ? cv::Scalar(0, 255, 0) : cv::Scalar(0, 0, 255);
    int center_x = img_width / 2 - 80;  // 居中显示
    cv::putText(serial_overlay, fmt::format("Serial: {}", gimbal.is_connected() ? "CONNECTED" : "DISCONNECTED"), 
                cv::Point(center_x, 250), cv::FONT_HERSHEY_SIMPLEX, 0.6, connection_color, 2);

    // 将串口数据叠加到图像上
    cv::Mat combined_img;
    cv::vconcat(img, serial_overlay, combined_img);

    cv::imshow("reprojection", combined_img);
    auto key = cv::waitKey(1);
    if (key == 'q') break;
  }

  quit = true;
  if (plan_thread.joinable()) plan_thread.join();
  gimbal.send(false, false, 0, 0, 0, 0, 0, 0);

  return 0;
}

#include <fmt/core.h>

#include <chrono>
#include <fstream>
#include <nlohmann/json.hpp>
#include <opencv2/opencv.hpp>

#include "tasks/auto_armor/aimer.hpp"
#include "tasks/auto_armor/solver.hpp"
#include "tasks/auto_armor/tracker.hpp"
#include "tasks/auto_armor/yolo.hpp"
#include "tasks/auto_armor/detector.hpp"
#include "tools/exiter.hpp"
#include "tools/img_tools.hpp"
#include "tools/logger.hpp"
#include "tools/math_tools.hpp"
#include "tools/plotter.hpp"

const std::string keys =
  "{help h usage ? |                   | 输出命令行参数说明 }"
  "{config-path c  | configs/test.yaml | yaml配置文件的路径}"
  "{start-index s  | 0                 | 视频起始帧下标    }"
  "{end-index e    | 0                 | 视频结束帧下标    }"
  "{@input-path    | assets/demo/demo  | avi和txt文件的路径}";

/**
 * @brief demo主运行函数
 * 
 * @param argc 
 * @param argv 
 * @return int 
 */
int main(int argc, char * argv[])
{
  // 读取命令行参数
  cv::CommandLineParser cli(argc, argv, keys);
  if (cli.has("help")) {
    cli.printMessage();
    return 0;
  }
  /************cli.get:从命令行中获取对应的值，例：************/
  /************input_file.txt --config-path=config.yaml --start-index=10 --end-index=20************/
  /************input_path = "input_file.txt";config_path = "config.yaml";start_index = 10;end_index = 20************/
  auto input_path = cli.get<std::string>(0);
  auto config_path = cli.get<std::string>("config-path"); //config_path就是configs文件夹下的yaml配置文件
  auto start_index = cli.get<int>("start-index");
//   auto end_index = cli.get<int>("end-index");

  tools::Plotter plotter; // 用于绘图的工具类
  tools::Exiter exiter; // 用于处理Ctrl+C信号的工具类

//   auto video_path = fmt::format("{}.avi", input_path);//对输入路径进行格式化，生成视频文件的路径
  auto text_path = fmt::format("{}.txt", input_path);//对输入路径进行格式化，生成文本文件的路径
//   cv::VideoCapture video(video_path);//使用 OpenCV 的 cv::VideoCapture 类从指定的 video_path 加载视频文件
  std::ifstream text(text_path);//打开指定的文本文件
  io::Camera camera(config_path);

  //切换视觉模型
  auto_aim::Detector detector(config_path, true);
//   auto_aim::YOLO yolo(config_path);

  auto_aim::Solver solver(config_path); //坐标变换器
  auto_aim::Tracker tracker(config_path, solver); //决策器
  auto_aim::Aimer aimer(config_path); //自瞄主文件

  cv::Mat img, drawing;
  auto t0 = std::chrono::steady_clock::now();
  std::chrono::steady_clock::time_point timestamp;

  auto_aim::Target last_target; //估计器
  io::Command last_command;
  double last_t = -1;

  static int frame_idx = 0;

//   video.set(cv::CAP_PROP_POS_FRAMES, start_index); //设置视频的起始帧位置
  for (int i = 0; i < start_index; i++) {
    double t, w, x, y, z; //时间，云台的四元数
    text >>  t>> w >> x >> y >> z; //从打开的文本文件中读取数据，并将其存储到变量中
  }

  while (!exiter.exit()) {

    camera.read(img, timestamp); //读取视频帧
    if (img.empty()) break; //如果读取的图像为空，则跳出循环

    double t, w, x, y, z;
    text >> t >> w >> x >> y >> z;

    /// 自瞄核心逻辑

    solver.set_R_gimbal2world({w, x, y, z}); //计算并设置从 gimbal 坐标系 到 world 坐标系 的旋转矩阵

    // auto yolo_start = std::chrono::steady_clock::now();
    // auto armors = yolo.detect(img);
/***************************三大步*********************************/
    auto detector_start = std::chrono::steady_clock::now();
    auto armors = detector.detect(img);

    auto tracker_start = std::chrono::steady_clock::now();
    auto targets = tracker.track(armors, timestamp);

    auto aimer_start = std::chrono::steady_clock::now();
    auto command = aimer.aim(targets, timestamp, 27, false);
/***************************三大步*********************************/
    if (
      !targets.empty() && aimer.debug_aim_point.valid &&
      std::abs(command.yaw - last_command.yaw) * 57.3 < 2)
      command.shoot = true;

    if (command.control) last_command = command;
    /// 调试输出

    auto finish = std::chrono::steady_clock::now();
    tools::logger()->info(
      "[{}] yolo: {:.1f}ms, tracker: {:.1f}ms, aimer: {:.1f}ms", frame_idx++,
    //   切换视觉方法
      tools::delta_time(tracker_start, detector_start) * 1e3,
    //   tools::delta_time(tracker_start, yolo_start) * 1e3,
      tools::delta_time(aimer_start, tracker_start) * 1e3,
      tools::delta_time(finish, aimer_start) * 1e3);

    tools::draw_text(
      img,
      fmt::format(
        "command is {},{:.2f},{:.2f},shoot:{}", command.control, command.yaw * 57.3,
        command.pitch * 57.3, command.shoot),
      {10, 60}, {154, 50, 205});

    Eigen::Quaternion gimbal_q = {w, x, y, z};
    tools::draw_text(
      img,
      fmt::format(
        "gimbal yaw{:.2f}", (tools::eulers(gimbal_q.toRotationMatrix(), 2, 1, 0) * 57.3)[0]),
      {10, 90}, {255, 255, 255});

    nlohmann::json data;

    // 装甲板原始观测数据
    data["armor_num"] = armors.size();
    if (!armors.empty()) {
      const auto & armor = armors.front();
      data["armor_x"] = armor.xyz_in_world[0];
      data["armor_y"] = armor.xyz_in_world[1];
      data["armor_yaw"] = armor.ypr_in_world[0] * 57.3;
      data["armor_yaw_raw"] = armor.yaw_raw * 57.3;
      data["armor_center_x"] = armor.center_norm.x;
      data["armor_center_y"] = armor.center_norm.y;
    }

    Eigen::Quaternion q{w, x, y, z};
    auto yaw = tools::eulers(q, 2, 1, 0)[0];
    data["gimbal_yaw"] = yaw * 57.3;
    data["cmd_yaw"] = command.yaw * 57.3;
    data["shoot"] = command.shoot;

    if (!targets.empty()) {
      auto target = targets.front();

      if (last_t == -1) {
        last_target = target;
        last_t = t;
        continue;
      }

      std::vector<Eigen::Vector4d> armor_xyza_list;

      // 当前帧target更新后
      armor_xyza_list = target.armor_xyza_list();
      for (const Eigen::Vector4d & xyza : armor_xyza_list) {
        auto image_points =
          solver.reproject_armor(xyza.head(3), xyza[3], target.armor_type, target.name);
        tools::draw_points(img, image_points, {0, 255, 0});
      }

      // aimer瞄准位置
      auto aim_point = aimer.debug_aim_point;
      Eigen::Vector4d aim_xyza = aim_point.xyza;
      auto image_points =
        solver.reproject_armor(aim_xyza.head(3), aim_xyza[3], target.armor_type, target.name);
      if (aim_point.valid) tools::draw_points(img, image_points, {0, 0, 255});

      // 观测器内部数据
      Eigen::VectorXd x = target.ekf_x();
      data["x"] = x[0];
      data["vx"] = x[1];
      data["y"] = x[2];
      data["vy"] = x[3];
      data["z"] = x[4];
      data["vz"] = x[5];
      data["a"] = x[6] * 57.3;
      data["w"] = x[7];
      data["r"] = x[8];
      data["l"] = x[9];
      data["h"] = x[10];
      data["last_id"] = target.last_id;

      // 卡方检验数据
      data["residual_yaw"] = target.ekf().data.at("residual_yaw");
      data["residual_pitch"] = target.ekf().data.at("residual_pitch");
      data["residual_distance"] = target.ekf().data.at("residual_distance");
      data["residual_angle"] = target.ekf().data.at("residual_angle");
      data["nis"] = target.ekf().data.at("nis");
      data["nees"] = target.ekf().data.at("nees");
      data["nis_fail"] = target.ekf().data.at("nis_fail");
      data["nees_fail"] = target.ekf().data.at("nees_fail");
      data["recent_nis_failures"] = target.ekf().data.at("recent_nis_failures");
    }

    plotter.plot(data);

    // cv::resize(img, img, {}, 0.5, 0.5);  // 显示时缩小图片尺寸
    cv::imshow("reprojection", img);
    if (cv::waitKey(1) == 'q') break;
  }

  return 0;
}

